//
// idma_xheep_wrapper.sv — iDMA wrapper matching x-heep's dma_subsystem interface.
//
// Replaces x-heep's simple DMA with the pulp-platform iDMA:
//   register frontend (idma_reg32_3d) + ND midend + OBI backend (idma_backend_rw_obi)
//
// The wrapper presents the same port interface as hw/ip/dma_subsystem/dma_subsystem.sv
// so it can be dropped into ao_peripheral_subsystem.sv.tpl without changing the
// surrounding template. The OBI master ports from the iDMA backend are mapped to
// the x-heep DMA read/write/addr master port arrays.
//
// For the PoC, this is a single-channel iDMA (NumRegs=1, NumStreams=1) with:
//   - 32-bit data width (matching x-heep OBI)
//   - 32-bit address width
//   - OBI read + OBI write backend
//   - 1D/2D/3D transfer support via ND midend
//   - Error handling (continue mode)
//
// Generation: The iDMA backend and register frontend are generated by
//   `util/gen_idma.py --entity backend --ids rw_obi` (see hw/vendor/mosaic/idma/)

`include "idma/typedef.svh"
`include "obi/typedef.svh"

module idma_xheep_wrapper #(
    parameter type reg_req_t = logic,
    parameter type reg_rsp_t = logic,
    parameter type obi_req_t = logic,
    parameter type obi_resp_t = logic,
    parameter type fifo_req_t = logic,
    parameter type fifo_resp_t = logic,
    parameter int unsigned GLOBAL_SLOT_NUM = 0,
    parameter int unsigned EXT_SLOT_NUM = 0
) (
    input logic clk_i,
    input logic rst_ni,

    // Clock gating (not used by iDMA — tie off)
    input logic clk_gate_en_ni [core_v_mini_mcu_pkg::DMA_CH_NUM-1:0],

    // Register bus slave
    input  reg_req_t reg_req_i,
    output reg_rsp_t reg_rsp_o,

    // OBI master ports — iDMA has 1 read + 1 write, mapped to the
    // first read/write master port. Additional ports are tied off.
    output obi_req_t  [core_v_mini_mcu_pkg::DMA_NUM_MASTER_PORTS-1:0] dma_read_req_o,
    input  obi_resp_t [core_v_mini_mcu_pkg::DMA_NUM_MASTER_PORTS-1:0] dma_read_resp_i,
    output obi_req_t  [core_v_mini_mcu_pkg::DMA_NUM_MASTER_PORTS-1:0] dma_write_req_o,
    input  obi_resp_t [core_v_mini_mcu_pkg::DMA_NUM_MASTER_PORTS-1:0] dma_write_resp_i,
    output obi_req_t  [core_v_mini_mcu_pkg::DMA_NUM_MASTER_PORTS-1:0] dma_addr_req_o,
    input  obi_resp_t [core_v_mini_mcu_pkg::DMA_NUM_MASTER_PORTS-1:0] dma_addr_resp_i,

    // Hardware FIFO (not used by iDMA — tie off)
    output fifo_req_t  [core_v_mini_mcu_pkg::DMA_CH_NUM-1:0] hw_fifo_req_o,
    input  fifo_resp_t [core_v_mini_mcu_pkg::DMA_CH_NUM-1:0] hw_fifo_resp_i,

    // Trigger slots (not used by iDMA — tie off)
    input logic [GLOBAL_SLOT_NUM-1:0] global_trigger_slot_i,
    input logic [EXT_SLOT_NUM-1:0]   ext_trigger_slot_i,

    // Control
    input logic [core_v_mini_mcu_pkg::DMA_CH_NUM-1:0] ext_dma_stop_i,
    input logic [core_v_mini_mcu_pkg::DMA_CH_NUM-1:0] hw_fifo_done_i,

    // External hw2reg (not used — iDMA has its own register frontend)
    input dma_reg_pkg::dma_hw2reg_t [core_v_mini_mcu_pkg::DMA_CH_NUM-1:0] external_hw2reg_i,

    // Interrupts
    output logic dma_done_intr_o,
    output logic dma_window_intr_o,

    // Status
    output logic [core_v_mini_mcu_pkg::DMA_CH_NUM-1:0] dma_ready_o,
    output logic [core_v_mini_mcu_pkg::DMA_CH_NUM-1:0] dma_done_o
);

  import idma_pkg::*;

  // ── Parameters ─────────────────────────────────────────────────
  localparam int unsigned DataWidth   = 32;
  localparam int unsigned AddrWidth   = 32;
  localparam int unsigned UserWidth   = 1;
  localparam int unsigned AxiIdWidth  = 1;
  localparam int unsigned TFLenWidth  = 32;
  localparam int unsigned NumDim      = 3;  // idma_reg32_3d emits 3D requests
  localparam int unsigned RepWidth    = 32;
  localparam int unsigned StrideWidth = 32;
  localparam int unsigned StrbWidth   = DataWidth / 8;
  localparam int unsigned NumRegs     = 1;  // single channel
  localparam int unsigned NumStreams  = 1;

  // ── Basic types ────────────────────────────────────────────────
  typedef logic [AddrWidth-1:0]   addr_t;
  typedef logic [DataWidth-1:0]   data_t;
  typedef logic [StrbWidth-1:0]   strb_t;
  typedef logic [UserWidth-1:0]   user_t;
  typedef logic [AxiIdWidth-1:0]  id_t;
  typedef logic [TFLenWidth-1:0]  tf_len_t;
  typedef logic [RepWidth-1:0]    reps_t;
  typedef logic [StrideWidth-1:0] strides_t;

  // ── iDMA request / response types (iDMA 0.6.5) ─────────────────
  // FULL_REQ_T is 4-arg; the `user` field defaults to `logic` (matches UserWidth=1).
  `IDMA_TYPEDEF_FULL_REQ_T(idma_req_t, id_t, addr_t, tf_len_t)
  `IDMA_TYPEDEF_FULL_RSP_T(idma_rsp_t, addr_t)
  `IDMA_TYPEDEF_D_REQ_T(idma_d_req_t, reps_t, strides_t)
  `IDMA_TYPEDEF_ND_REQ_T(idma_nd_req_t, idma_req_t, idma_d_req_t)

  // ── pulp-platform OBI types (the iDMA backend's native master bus) ──
  `OBI_TYPEDEF_MINIMAL_A_OPTIONAL(obi_a_optional_t)
  `OBI_TYPEDEF_MINIMAL_R_OPTIONAL(obi_r_optional_t)
  `OBI_TYPEDEF_TYPE_A_CHAN_T(obi_a_chan_t, addr_t, data_t, strb_t, id_t, obi_a_optional_t)
  `OBI_TYPEDEF_TYPE_R_CHAN_T(obi_r_chan_t, data_t, id_t, obi_r_optional_t)
  `OBI_TYPEDEF_REQ_T(idma_obi_req_t, obi_a_chan_t)
  `OBI_TYPEDEF_RSP_T(idma_obi_rsp_t, obi_r_chan_t)

  // OBI read/write meta channels (the address-phase metadata, per idma_obi.yml)
  typedef struct packed {obi_a_chan_t a_chan;} obi_read_meta_channel_t;
  typedef struct packed {obi_read_meta_channel_t obi;} read_meta_channel_t;
  typedef struct packed {obi_a_chan_t a_chan;} obi_write_meta_channel_t;
  typedef struct packed {obi_write_meta_channel_t obi;} write_meta_channel_t;

  // ── Internal signals ───────────────────────────────────────────
  reg_req_t [NumRegs-1:0] ctrl_req;
  reg_rsp_t [NumRegs-1:0] ctrl_rsp;
  assign ctrl_req   = reg_req_i;
  assign reg_rsp_o  = ctrl_rsp;

  idma_nd_req_t nd_req;
  logic         nd_req_valid, nd_req_ready;
  idma_rsp_t    nd_rsp;
  logic         nd_rsp_valid, nd_rsp_ready;

  idma_req_t    burst_req;
  logic         burst_req_valid, burst_req_ready;
  idma_rsp_t    burst_rsp;
  logic         burst_rsp_valid, burst_rsp_ready;

  logic [31:0]  next_id, completed_id;
  idma_pkg::idma_busy_t be_busy;
  logic         nd_busy;

  idma_obi_req_t obi_read_req, obi_write_req;
  idma_obi_rsp_t obi_read_rsp, obi_write_rsp;

  idma_pkg::idma_eh_req_t eh_req;
  logic                   eh_req_valid, eh_req_ready;

  // ── Register frontend: memory-mapped descriptor → ND request ───
  idma_reg32_3d #(
    .NumRegs    (NumRegs),
    .NumStreams (NumStreams),
    .reg_req_t  (reg_req_t),
    .reg_rsp_t  (reg_rsp_t),
    .dma_req_t  (idma_nd_req_t)
  ) i_reg_fe (
    .clk_i,
    .rst_ni,
    .dma_ctrl_req_i (ctrl_req),
    .dma_ctrl_rsp_o (ctrl_rsp),
    .dma_req_o      (nd_req),
    .req_valid_o    (nd_req_valid),
    .req_ready_i    (nd_req_ready),
    .next_id_i      (next_id),
    .stream_idx_o   (),
    .done_id_i      (completed_id),
    .busy_i         (be_busy),
    .midend_busy_i  (nd_busy)
  );

  // ── Transfer ID generator ──────────────────────────────────────
  idma_transfer_id_gen #(
    .IdWidth (32)
  ) i_id_gen (
    .clk_i,
    .rst_ni,
    .issue_i     (nd_req_valid & nd_req_ready),
    .retire_i    (nd_rsp_valid & nd_rsp_ready),
    .next_o      (next_id),
    .completed_o (completed_id)
  );

  // ── ND midend: ND descriptor → 1D bursts ───────────────────────
  localparam logic [NumDim-1:0][31:0] RepWidths = '{default: RepWidth};

  idma_nd_midend #(
    .NumDim        (NumDim),
    .addr_t        (addr_t),
    .idma_req_t    (idma_req_t),
    .idma_rsp_t    (idma_rsp_t),
    .idma_nd_req_t (idma_nd_req_t),
    .RepWidths     (RepWidths)
  ) i_nd_midend (
    .clk_i,
    .rst_ni,
    .nd_req_i          (nd_req),
    .nd_req_valid_i    (nd_req_valid),
    .nd_req_ready_o    (nd_req_ready),
    .nd_rsp_o          (nd_rsp),
    .nd_rsp_valid_o    (nd_rsp_valid),
    .nd_rsp_ready_i    (nd_rsp_ready),
    .burst_req_o       (burst_req),
    .burst_req_valid_o (burst_req_valid),
    .burst_req_ready_i (burst_req_ready),
    .burst_rsp_i       (burst_rsp),
    .burst_rsp_valid_i (burst_rsp_valid),
    .burst_rsp_ready_o (burst_rsp_ready),
    .busy_o            (nd_busy)
  );
  assign nd_rsp_ready = 1'b1;

  // ── OBI backend: 1D burst → pulp-OBI read + write masters ──────
  idma_backend_rw_obi #(
    .DataWidth           (DataWidth),
    .AddrWidth           (AddrWidth),
    .UserWidth           (UserWidth),
    .AxiIdWidth          (AxiIdWidth),
    .NumAxInFlight       (3),
    .BufferDepth         (3),
    .TFLenWidth          (TFLenWidth),
    .MemSysDepth         (0),
    .RAWCouplingAvail    (1'b0),
    .MaskInvalidData     (1'b1),
    .HardwareLegalizer   (1'b1),
    .RejectZeroTransfers (1'b1),
    .ErrorCap            (idma_pkg::NO_ERROR_HANDLING),
    .idma_req_t          (idma_req_t),
    .idma_rsp_t          (idma_rsp_t),
    .idma_eh_req_t       (idma_pkg::idma_eh_req_t),
    .idma_busy_t         (idma_pkg::idma_busy_t),
    .obi_req_t           (idma_obi_req_t),
    .obi_rsp_t           (idma_obi_rsp_t),
    .read_meta_channel_t (read_meta_channel_t),
    .write_meta_channel_t(write_meta_channel_t)
  ) i_backend (
    .clk_i,
    .rst_ni,
    .testmode_i      (1'b0),
    .idma_req_i      (burst_req),
    .req_valid_i     (burst_req_valid),
    .req_ready_o     (burst_req_ready),
    .idma_rsp_o      (burst_rsp),
    .rsp_valid_o     (burst_rsp_valid),
    .rsp_ready_i     (burst_rsp_ready),
    .idma_eh_req_i   (eh_req),
    .eh_req_valid_i  (eh_req_valid),
    .eh_req_ready_o  (eh_req_ready),
    .obi_read_req_o  (obi_read_req),
    .obi_read_rsp_i  (obi_read_rsp),
    .obi_write_req_o (obi_write_req),
    .obi_write_rsp_i (obi_write_rsp),
    .busy_o          (be_busy)
  );
  assign eh_req       = '0;
  assign eh_req_valid = 1'b0;

  // ── pulp-OBI ⇄ x-heep OBI conversion (read + write masters) ────
  // x-heep obi_req_t = {req, we, be, addr, wdata}; obi_resp_t = {gnt, rvalid, rdata}.
  // pulp-OBI req = {req, a:{addr, we, be, wdata, aid, a_optional}, ...};
  // pulp-OBI rsp = {gnt, rvalid, r:{rdata, rid, err, r_optional}}.
  // Local x-heep OBI structs (member access on a packed-array element is not
  // supported by Verilator, so convert via locals then assign whole elements).
  obi_req_t  rd_req_xheep, wr_req_xheep;
  obi_resp_t rd_resp_xheep, wr_resp_xheep;
  assign rd_resp_xheep = dma_read_resp_i[0];
  assign wr_resp_xheep = dma_write_resp_i[0];

  always_comb begin
    rd_req_xheep       = '0;
    rd_req_xheep.req   = obi_read_req.req;
    rd_req_xheep.we    = obi_read_req.a.we;
    rd_req_xheep.be    = obi_read_req.a.be;
    rd_req_xheep.addr  = obi_read_req.a.addr;
    rd_req_xheep.wdata = obi_read_req.a.wdata;

    obi_read_rsp         = '0;
    obi_read_rsp.gnt     = rd_resp_xheep.gnt;
    obi_read_rsp.rvalid  = rd_resp_xheep.rvalid;
    obi_read_rsp.r.rdata = rd_resp_xheep.rdata;

    wr_req_xheep       = '0;
    wr_req_xheep.req   = obi_write_req.req;
    wr_req_xheep.we    = obi_write_req.a.we;
    wr_req_xheep.be    = obi_write_req.a.be;
    wr_req_xheep.addr  = obi_write_req.a.addr;
    wr_req_xheep.wdata = obi_write_req.a.wdata;

    obi_write_rsp         = '0;
    obi_write_rsp.gnt     = wr_resp_xheep.gnt;
    obi_write_rsp.rvalid  = wr_resp_xheep.rvalid;
    obi_write_rsp.r.rdata = wr_resp_xheep.rdata;
  end

  assign dma_read_req_o[0]  = rd_req_xheep;
  assign dma_write_req_o[0] = wr_req_xheep;

  // ── Interrupts ─────────────────────────────────────────────────
  logic transfer_done;
  assign transfer_done = nd_rsp_valid & nd_rsp_ready;
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) dma_done_intr_o <= 1'b0;
    else         dma_done_intr_o <= transfer_done;
  end
  assign dma_window_intr_o = 1'b0;

  // ── Status ─────────────────────────────────────────────────────
  assign dma_ready_o[0] = ~nd_busy;
  assign dma_done_o[0]  = transfer_done;
  for (genvar i = 1; i < core_v_mini_mcu_pkg::DMA_CH_NUM; i++) begin : gen_unused_ch
    assign dma_ready_o[i] = 1'b0;
    assign dma_done_o[i]  = 1'b0;
  end

  // ── Tie off the addr master ports + extra read/write ports ─────
  for (genvar i = 1; i < core_v_mini_mcu_pkg::DMA_NUM_MASTER_PORTS; i++) begin : gen_unused_rw
    assign dma_read_req_o[i]  = '0;
    assign dma_write_req_o[i] = '0;
  end
  for (genvar i = 0; i < core_v_mini_mcu_pkg::DMA_NUM_MASTER_PORTS; i++) begin : gen_unused_addr
    assign dma_addr_req_o[i]  = '0;
  end

  // ── Tie off the hardware FIFO ports ────────────────────────────
  for (genvar i = 0; i < core_v_mini_mcu_pkg::DMA_CH_NUM; i++) begin : gen_fifo_tie
    assign hw_fifo_req_o[i] = '0;
  end

endmodule : idma_xheep_wrapper
